"use client"

import { useState, useEffect } from "react"
import { Upload, Search, BookOpen, AlertCircle, Plus, Folder, Trash2, MessageSquare } from "lucide-react"
import { Card } from "@/components/ui/card"
import FileUploadZone from "@/components/file-upload-zone"
import PapersList from "@/components/papers-list"
import QueryInterface from "@/components/query-interface"
import ChatPanel from "@/components/chat-panel"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogTrigger,
  DialogFooter
} from "@/components/ui/dialog"

export default function Home() {
  const [workspaces, setWorkspaces] = useState([])
  const [selectedWorkspaceId, setSelectedWorkspaceId] = useState("")
  const [papers, setPapers] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState("")
  const [activeTab, setActiveTab] = useState("upload")
  const [newWorkspaceName, setNewWorkspaceName] = useState("")
  const [isNewWorkspaceDialogOpen, setIsNewWorkspaceDialogOpen] = useState(false)

  useEffect(() => {
    fetchWorkspaces()
  }, [])

  useEffect(() => {
    if (selectedWorkspaceId) {
      fetchPapers(selectedWorkspaceId)
    }
  }, [selectedWorkspaceId])

  // Polling for summaries if any paper is missing one
  useEffect(() => {
    let interval: NodeJS.Timeout;
    const needsPolling = papers.some((p: any) => !p.metadata.summary);
    
    if (needsPolling && selectedWorkspaceId) {
      interval = setInterval(() => {
        fetchPapers(selectedWorkspaceId);
      }, 3000);
    }
    
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [papers, selectedWorkspaceId]);

  const fetchWorkspaces = async () => {
    try {
      const response = await fetch("/api/workspaces")
      const data = await response.json()
      setWorkspaces(data.workspaces || [])
      
      if (data.workspaces?.length > 0 && !selectedWorkspaceId) {
        setSelectedWorkspaceId(data.workspaces[0].id)
      }
    } catch (err) {
      console.error("Failed to fetch workspaces", err)
    }
  }

  const fetchPapers = async (workspaceId: string) => {
    try {
      const response = await fetch(`/api/papers?workspaceId=${workspaceId}`)
      const data = await response.json()
      setPapers(data.papers || [])
      setError("")
    } catch (err) {
      setError("Failed to fetch papers")
      console.error(err)
    }
  }

  const handleCreateWorkspace = async () => {
    if (!newWorkspaceName.trim()) return
    
    try {
      const response = await fetch("/api/workspaces", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newWorkspaceName })
      })
      const data = await response.json()
      if (data.workspace) {
        setWorkspaces([data.workspace, ...workspaces])
        setSelectedWorkspaceId(data.workspace.id)
        setIsNewWorkspaceDialogOpen(false)
        setNewWorkspaceName("")
      }
    } catch (err) {
      console.error("Failed to create workspace", err)
    }
  }

  const handleDeleteWorkspace = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation()
    if (!confirm("Delete this workspace and all its papers?")) return
    
    try {
      await fetch(`/api/workspaces?id=${id}`, { method: "DELETE" })
      setWorkspaces(workspaces.filter((w: any) => w.id !== id))
      if (selectedWorkspaceId === id && workspaces.length > 1) {
        setSelectedWorkspaceId(workspaces[0].id === id ? workspaces[1].id : workspaces[0].id)
      }
    } catch (err) {
      console.error("Failed to delete workspace", err)
    }
  }

  const handleUploadSuccess = () => {
    fetchPapers(selectedWorkspaceId)
    setActiveTab("query")
  }

  return (
    <main className="min-h-screen bg-slate-950 text-slate-200">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-xl sticky top-0 z-50">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-blue-600">
                <BookOpen className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white leading-tight">Research RAG</h1>
                <p className="text-xs text-slate-400">Advanced AI Document Analysis</p>
              </div>
            </div>
            
            <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-800 border border-slate-700">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
                <span className="text-xs font-medium text-slate-300 uppercase tracking-wider">Cloud Processing Alpha</span>
              </div>
            </div>
          </div>
        </div>
      </header>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          
          {/* Sidebar: Workspaces */}
          <aside className="lg:col-span-1 space-y-6">
            <div className="flex items-center justify-between mb-2">
              <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-widest px-2">Workspaces</h2>
              <Dialog open={isNewWorkspaceDialogOpen} onOpenChange={setIsNewWorkspaceDialogOpen}>
                <DialogTrigger asChild>
                  <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400 hover:text-white hover:bg-slate-800">
                    <Plus className="w-4 h-4" />
                  </Button>
                </DialogTrigger>
                <DialogContent className="bg-slate-900 border-slate-800 text-white">
                  <DialogHeader>
                    <DialogTitle>Create New Workspace</DialogTitle>
                  </DialogHeader>
                  <div className="py-4">
                    <Input 
                      placeholder="e.g. Biology Research, NLP Papers..." 
                      value={newWorkspaceName}
                      onChange={(e) => setNewWorkspaceName(e.target.value)}
                      className="bg-slate-800 border-slate-700"
                    />
                  </div>
                  <DialogFooter>
                    <Button variant="ghost" onClick={() => setIsNewWorkspaceDialogOpen(false)}>Cancel</Button>
                    <Button className="bg-blue-600 hover:bg-blue-700" onClick={handleCreateWorkspace}>Create</Button>
                  </DialogFooter>
                </DialogContent>
              </Dialog>
            </div>
            
            <nav className="space-y-1">
              {workspaces.map((ws: any) => (
                <button
                  key={ws.id}
                  onClick={() => setSelectedWorkspaceId(ws.id)}
                  className={`w-full flex items-center justify-between px-3 py-2.5 rounded-lg text-sm transition-all group ${
                    selectedWorkspaceId === ws.id 
                    ? "bg-blue-600/10 text-blue-400 border border-blue-500/20 shadow-[0_0_15px_rgba(37,99,235,0.05)]" 
                    : "text-slate-400 hover:text-slate-200 hover:bg-slate-800/50 border border-transparent"
                  }`}
                >
                  <div className="flex items-center gap-2.5">
                    <Folder className={`w-4 h-4 ${selectedWorkspaceId === ws.id ? "text-blue-500" : "text-slate-500"}`} />
                    <span className="font-medium truncate max-w-[120px]">{ws.name}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] bg-slate-800 px-1.5 py-0.5 rounded text-slate-500">{ws._count?.papers || 0}</span>
                    {ws.name !== "Default" && (
                      <Trash2 
                        className="w-3.5 h-3.5 text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity" 
                        onClick={(e) => handleDeleteWorkspace(ws.id, e)}
                      />
                    )}
                  </div>
                </button>
              ))}
            </nav>

            <Card className="bg-slate-900/40 border-slate-800/50 p-4">
              <h3 className="text-xs font-bold text-slate-500 uppercase mb-3">Workspace Stats</h3>
              <div className="space-y-2.5">
                <div className="flex justify-between items-center">
                  <span className="text-xs text-slate-400">Total Papers</span>
                  <span className="text-xs font-mono text-white">{papers.length}</span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs text-slate-400">Total Tokens</span>
                  <span className="text-xs font-mono text-white">~{papers.reduce((acc, p: any) => acc + (p.metadata.chunks * 500), 0).toLocaleString()}</span>
                </div>
              </div>
            </Card>
          </aside>

          {/* Main Area */}
          <div className="lg:col-span-3">
            {error && (
              <Card className="mb-6 bg-red-950/20 border-red-900/50 text-red-400 p-4 flex items-center gap-3">
                <AlertCircle className="w-5 h-5 shrink-0" />
                <span className="text-sm font-medium">{error}</span>
              </Card>
            )}

            <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
              <div className="flex items-center justify-between mb-6">
                <TabsList className="bg-slate-900 border border-slate-800 p-1">
                  <TabsTrigger value="upload" className="data-[state=active]:bg-slate-800 data-[state=active]:text-blue-400">
                    <Upload className="w-4 h-4 mr-2" />
                    Upload
                  </TabsTrigger>
                  <TabsTrigger value="papers" className="data-[state=active]:bg-slate-800 data-[state=active]:text-blue-400">
                    <BookOpen className="w-4 h-4 mr-2" />
                    Collection
                  </TabsTrigger>
                  <TabsTrigger value="query" className="data-[state=active]:bg-slate-800 data-[state=active]:text-blue-400">
                    <Search className="w-4 h-4 mr-2" />
                    Explorer
                  </TabsTrigger>
                  <TabsTrigger value="chat" className="data-[state=active]:bg-slate-800 data-[state=active]:text-blue-400">
                    <MessageSquare className="w-4 h-4 mr-2" />
                    Chat
                  </TabsTrigger>
                </TabsList>
              </div>

              <div className="transition-all duration-300">
                <TabsContent value="upload">
                  <FileUploadZone workspaceId={selectedWorkspaceId} onUploadSuccess={handleUploadSuccess} />
                </TabsContent>

                <TabsContent value="papers">
                  <PapersList papers={papers} onPapersChange={() => fetchPapers(selectedWorkspaceId)} />
                </TabsContent>

                <TabsContent value="query">
                  <QueryInterface papers={papers} workspaceId={selectedWorkspaceId} />
                </TabsContent>

                <TabsContent value="chat">
                  <ChatPanel papers={papers} workspaceId={selectedWorkspaceId} />
                </TabsContent>
              </div>
            </Tabs>
          </div>
        </div>
      </div>
    </main>
  )
}

